VALUES
  ('disabled-57f41407-moex-00646', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「哈里．杜魯門首次參加競選並一舉成功，成了美國總統。有記者去採訪 杜魯門的母親，問她：『你肯定為你的兒子感到自豪。』 她說：『不錯， 我為我兒子哈里感到自豪。但是，我也為另一個兒子自豪，他現在正在地 裡挖馬鈴薯。』」上文的主旨是：', '["媒體採訪應具有道德素養", "政治與農業有著相通共性", "母親眼中的自豪，是孩子各自努力，各有成就", "即使是同胞兄弟，後天的努力仍影響發展結果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00647', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「我們總是輕忽失敗的經驗，失敗是個衝擊，但它的特殊力量讓我們更了 解自己。逆境其實可能是你一生中最好的經歷。」下列選項，何者與題旨 最接近？', '["滿招損，謙受益", "不以一眚掩大德", "三折肱，知為良醫", "吾生也有涯，而知也無涯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00648', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '有關公文的撰擬，下列選項錯誤的是：', '["公文寫作切忌主觀、偏見", "公文文字應簡淺明確，並加具標點符號", "為達到目的，公文語氣要謙卑，文詞要有彈性", "機關內部各單位撰擬文稿，文字用語、結構格式應力求一致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00649', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列選項所使用的期望及目的語，何者不恰當？', '["教育部體育署行文教育部／請查照", "經濟部水利署行文經濟部／請核備", "財政部行文財政部臺北國稅局／希照辦", "內政部警政署行文內政部消防署／請惠允見復"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00650', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列關於公文的敘述正確的是：', '["內政部對行政院報告時用「呈」", "市民與臺北市政府間之申請與答復時用「函」", "總統與立法院、考試院公文往復時使用「咨」", "上級機關對所屬下級機關有所指示、交辦、批復時用「令」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00651', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '內政部行文考試院，所使用的稱謂語，正確的是：', '["貴院", "大院", "鈞院", "臺院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00652', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲至位處Ａ地、由丙公司經營之觀光大飯店渡假，因甲感覺該飯店服務人 員態度不佳，使用其在Ｂ地之住所電腦，連接網路於飯店評價網站上發表 公開評論。嗣丙公司經理丁於其在Ｃ地之住家內觀看到甲上開評論而回報 丙公司。經丙公司法務人員於該觀光大飯店內電腦確認該評論後，丙公司 認為甲所述不實，侵害其商譽，爰依侵權行為法律關係，起訴請求甲賠償。 關於本件訴訟管轄權，下列敘述何者正確？', '["因受評論之觀光大飯店位處Ａ地，本件訴訟專屬於Ａ地之法院管轄", "因甲使用其在Ｂ地之住處電腦上網發表評論，本件訴訟僅能由Ｂ地之法 院管轄", "因丁於其在Ｃ地之住家內觀看到甲上開評論，本件訴訟亦得由Ｃ地之法 院管轄", "因甲使用其在Ｂ地之住處電腦上網發表評論，由丁於其在Ｃ地之住家內 瀏覽該評論，所以Ａ地之法院就本件訴訟沒有管轄權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00653', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，非屬法官應自行迴避之情形？', '["法官曾為原告之法定代理人", "法官與被告為大學同班同學", "法官與原告為同父異母兄弟", "法官與原告訂有婚約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00654', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A、B、C、D、E 均為X之子女，X於民國108 年死亡，E已拋棄繼承， A於X死亡後發覺X於106年間已將甲房地以買賣為原因移轉登記予B， 而 X 名下已無財產，認為 B 未給付買賣價金予 X。A 擬起訴請求 B 返還 買賣價金，下列敘述何者錯誤？', '["A應與C、D、E一同為原告，當事人適格始無欠缺", "如 C 拒絕同為原告而無正當理由者，法院得依 A 聲請，以裁定命 C 於 一定期間內追加為原告。逾期未追加者，視為已一同起訴", "如C拒絕同為原告而無正當理由者，法院以裁定命C追加為原告前，應 使C有陳述意見之機會", "如C所在不明，經A聲請命為追加，法院認其聲請為正當者，得以裁定 將C列為原告。但C於第一次言詞辯論期日前陳明拒絕為原告之理由， 經法院認為正當者，得撤銷原裁定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00655', 'disabled-57f41407', 'disabled-57f41407-moex-110-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟能力，下列敘述何者錯誤？', '["能獨立以法律行為負義務者，有訴訟能力", "具有訴訟能力之當事人，必須自己為各項訴訟行為", "具有當事人能力者，未必具有訴訟能力", "訴訟前為合意管轄之約定者，必須具備訴訟能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "21ff34e8b3c0", "answer_pdf_sha1": "771e36403dd4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0407", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
